  is_active = TRUE;

VALUES ('BTS', 'BTS', 'BTS - KRPTK/KRKAN/KRPUS/CNSHA/VNSGN/THLCH/THBKK', 'ROUND', 'BTS full rotation imported from JRC ECDIS route sheets.', TRUE);


COMMIT;
